import { err, ok } from "@diffgazer/core/result";
import type { AgentStreamEvent, StepEvent } from "@diffgazer/core/schemas/events";
import type { Lens, ReviewIssue } from "@diffgazer/core/schemas/review";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import type { AIClient } from "../ai/types.js";
import type { ParsedDiff } from "../diff/types.js";
import { runLensAnalysis } from "./analysis.js";
import type { AgentRunContext } from "./types.js";

const CORRECTNESS_LENS: Lens = {
  id: "correctness",
  name: "Correctness",
  description: "Find bugs and logic errors",
  systemPrompt: "You are a code reviewer.",
  severityRubric: {
    blocker: "Crashes or data loss",
    high: "Significant bug",
    medium: "Minor bug",
    low: "Code smell",
    nit: "Style issue",
  },
};

function makeDiff(fileCount = 1): ParsedDiff {
  const files = Array.from({ length: fileCount }, (_, i) => ({
    filePath: `src/file-${i}.ts`,
    previousPath: null,
    operation: "modify" as const,
    hunks: [
      {
        oldStart: 1,
        oldCount: 5,
        newStart: 1,
        newCount: 7,
        content: "line1\nline2\nline3\nline4\nline5\nline6\nline7",
      },
    ],
    rawDiff: "diff --git a/file b/file\n+added line\n-removed line",
    stats: { additions: 2, deletions: 1, sizeBytes: 100 },
  }));

  return {
    files,
    totalStats: {
      filesChanged: fileCount,
      additions: fileCount * 2,
      deletions: fileCount,
      totalSizeBytes: fileCount * 100,
    },
  };
}

function makeContext(): AgentRunContext {
  return {
    traceId: "trace-1",
    spanId: "span-1",
    parentSpanId: "parent-span-1",
  };
}

function makeIssue(id: string, file: string): ReviewIssue {
  return {
    id,
    file,
    severity: "medium",
    category: "correctness",
    title: `Issue ${id}`,
    rationale: "test rationale",
    recommendation: "fix it",
    suggested_patch: null,
    confidence: 0.9,
    symptom: "broken",
    whyItMatters: "matters",
    evidence: [],
    line_start: 1,
    line_end: 5,
  } as ReviewIssue;
}

function makeMockAIClient(result: Awaited<ReturnType<AIClient["generate"]>>): AIClient {
  return {
    provider: "openrouter",
    generate: vi.fn().mockResolvedValue(result),
    generateStream: vi.fn(),
  };
}

describe("runLensAnalysis", () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("emits the agent, file, tool, and issue events in order on success", async () => {
    const diff = makeDiff(2);
    const issues = [makeIssue("1", "src/file-0.ts")];
    const client = makeMockAIClient(
      ok({ summary: "Found 1 issue", issues }),
    );
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
    );

    await vi.advanceTimersByTimeAsync(100);
    const result = await promise;

    expect(result.ok).toBe(true);

    const eventTypes = events.map((e) => e.type);

    expect(eventTypes).toContain("agent_start");
    expect(eventTypes).toContain("agent_thinking");
    expect(eventTypes).toContain("agent_progress");

    expect(eventTypes.filter((t) => t === "file_start")).toHaveLength(2);
    expect(eventTypes.filter((t) => t === "file_complete")).toHaveLength(2);

    expect(eventTypes.filter((t) => t === "tool_start")).toHaveLength(2);
    expect(eventTypes.filter((t) => t === "tool_end")).toHaveLength(2);

    expect(eventTypes.filter((t) => t === "issue_found")).toHaveLength(1);
    expect(eventTypes).toContain("agent_complete");

    if (result.ok) {
      expect(result.value.lensId).toBe("correctness");
      expect(result.value.lensName).toBe("Correctness");
      expect(result.value.issues).toHaveLength(1);
    }
  });

  it("propagates the AI client error and emits an agent_error event", async () => {
    const diff = makeDiff(1);
    const client = makeMockAIClient(
      err({ code: "MODEL_ERROR" as const, message: "Model failed" }),
    );
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
    );
    await vi.advanceTimersByTimeAsync(100);
    const result = await promise;

    expect(result.ok).toBe(false);
    if (!result.ok) {
      expect(result.error.code).toBe("MODEL_ERROR");
    }

    const errorEvents = events.filter((e) => e.type === "agent_error");
    expect(errorEvents).toHaveLength(1);
    const errorEvent = errorEvents[0] as Extract<AgentStreamEvent, { type: "agent_error" }>;
    expect(errorEvent.error).toContain("MODEL_ERROR");
  });

  it("stops scanning additional files once the abort signal fires", async () => {
    const diff = makeDiff(5);
    const client = makeMockAIClient(ok({ summary: "Clean", issues: [] }));
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);
    const controller = new AbortController();

    setTimeout(() => controller.abort(), 0);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
      undefined,
      controller.signal,
    );

    await vi.advanceTimersByTimeAsync(10);
    const result = await promise;

    const fileStartEvents = events.filter((e) => e.type === "file_start");
    expect(fileStartEvents.length).toBeLessThanOrEqual(5);

    expect(result.ok).toBe(true);
  });

  it("backfills empty issue evidence from the diff", async () => {
    const diff = makeDiff(1);
    const issue = makeIssue("1", "src/file-0.ts");
    issue.evidence = [];

    const client = makeMockAIClient(
      ok({ summary: "Found issue", issues: [issue] }),
    );
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
    );
    await vi.advanceTimersByTimeAsync(100);
    const result = await promise;

    expect(result.ok).toBe(true);
    if (result.ok) {
      const resultIssue = result.value.issues[0]!;
      expect(resultIssue.evidence).toBeDefined();
      expect(resultIssue.evidence?.length).toBeGreaterThan(0);
    }
  });

  it("filters out issues referencing files not in the reviewed diff", async () => {
    const diff = makeDiff(1); // Only src/file-0.ts
    const validIssue = makeIssue("1", "src/file-0.ts");
    const hallucinatedIssue = makeIssue("2", "src/nonexistent.ts");
    const client = makeMockAIClient(
      ok({ summary: "Found 2 issues", issues: [validIssue, hallucinatedIssue] }),
    );
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
    );
    await vi.advanceTimersByTimeAsync(100);
    const result = await promise;

    expect(result.ok).toBe(true);
    if (result.ok) {
      expect(result.value.issues).toHaveLength(1);
      expect(result.value.issues[0]?.file).toBe("src/file-0.ts");
    }

    const issueEvents = events.filter((e) => e.type === "issue_found");
    expect(issueEvents).toHaveLength(1);
  });

  it("stops emitting progress events after the generate call rejects", async () => {
    const diff = makeDiff(1);
    const rejectError = new Error("Network failure");
    const client: AIClient = {
      provider: "openrouter",
      generate: vi.fn().mockRejectedValue(rejectError),
      generateStream: vi.fn(),
    };
    const events: Array<AgentStreamEvent | StepEvent> = [];
    const onEvent = (e: AgentStreamEvent | StepEvent) => events.push(e);

    const promise = runLensAnalysis(
      client,
      CORRECTNESS_LENS,
      diff,
      onEvent,
      makeContext(),
    );

    // Await the rejection immediately so it doesn't leak as unhandled
    await expect(promise).rejects.toThrow("Network failure");

    // Timer should be cleaned up - advancing time further should not add progress events
    const eventCountBefore = events.filter((e) => e.type === "agent_progress").length;
    await vi.advanceTimersByTimeAsync(15000);
    const eventCountAfter = events.filter((e) => e.type === "agent_progress").length;
    expect(eventCountAfter).toBe(eventCountBefore);
  });
});

import { randomUUID } from "node:crypto";
import type { Result } from "@diffgazer/core/result";
import { ok } from "@diffgazer/core/result";
import type { AgentStreamEvent, StepEvent } from "@diffgazer/core/schemas/events";
import { AGENT_METADATA, LENS_TO_AGENT } from "@diffgazer/core/schemas/events";
import type { Lens, ReviewIssue, ReviewResult } from "@diffgazer/core/schemas/review";
import { ReviewResultSchema } from "@diffgazer/core/schemas/review";
import { pluralize } from "@diffgazer/core/strings";
import type { AIClient, AIError } from "../ai/types.js";
import type { ParsedDiff } from "../diff/types.js";
import { ensureIssueEvidence } from "./issues.js";
import { buildReviewPrompt } from "./prompts.js";
import type { AgentRunContext, LensResult } from "./types.js";

function estimateTokens(text: string): number {
  if (!text) return 0;
  return Math.ceil(text.length / 4);
}

function getThinkingMessage(lens: Lens): string {
  switch (lens.id) {
    case "correctness":
      return "Analyzing diff for bugs and logic errors...";
    case "security":
      return "Analyzing diff for security vulnerabilities...";
    case "performance":
      return "Analyzing diff for performance issues...";
    case "simplicity":
      return "Analyzing diff for complexity and maintainability...";
    case "tests":
      return "Analyzing diff for test coverage and quality...";
    default:
      return `Analyzing diff with ${lens.name} lens...`;
  }
}

export async function runLensAnalysis(
  client: AIClient,
  lens: Lens,
  diff: ParsedDiff,
  onEvent: (event: AgentStreamEvent | StepEvent) => void,
  context: AgentRunContext,
  projectContext?: string,
  signal?: AbortSignal
): Promise<Result<LensResult, AIError>> {
  const agentId = LENS_TO_AGENT[lens.id];
  const agentMeta = AGENT_METADATA[agentId];
  const startedAt = Date.now();
  const traceId = context.traceId;
  const spanId = context.spanId;
  const parentSpanId = context.parentSpanId;

  onEvent({
    type: "agent_start",
    agent: agentMeta,
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  onEvent({
    type: "agent_thinking",
    agent: agentId,
    thought: getThinkingMessage(lens),
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  onEvent({
    type: "agent_progress",
    agent: agentId,
    progress: 15,
    message: `Gathering context (${diff.files.length} files)`,
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  for (let i = 0; i < diff.files.length; i++) {
    if (signal?.aborted) break;
    const file = diff.files[i]!;

    onEvent({
      type: "file_start",
      file: file.filePath,
      index: i,
      total: diff.files.length,
      timestamp: new Date().toISOString(),
      agent: agentId,
      scope: "agent",
      traceId,
      spanId,
      parentSpanId,
    });

    const lineCount = file.rawDiff.split("\n").length;
    const startLine = file.hunks[0]?.newStart ?? 1;
    const lastHunk = file.hunks[file.hunks.length - 1];
    const endLine = lastHunk ? lastHunk.newStart + lastHunk.newCount - 1 : startLine;

    const toolSpanId = randomUUID();
    onEvent({
      type: "tool_start",
      agent: agentId,
      tool: "readFileContext",
      input: `${file.filePath}:${startLine}-${endLine}`,
      timestamp: new Date().toISOString(),
      traceId,
      spanId: toolSpanId,
      parentSpanId: spanId,
    });

    onEvent({
      type: "tool_end",
      agent: agentId,
      tool: "readFileContext",
      summary: `Read ${lineCount} lines from ${file.filePath}`,
      status: "success",
      timestamp: new Date().toISOString(),
      traceId,
      spanId: toolSpanId,
      parentSpanId: spanId,
    });

    onEvent({
      type: "file_complete",
      file: file.filePath,
      index: i,
      total: diff.files.length,
      timestamp: new Date().toISOString(),
      agent: agentId,
      scope: "agent",
      traceId,
      spanId,
      parentSpanId,
    });

    const progress = diff.files.length > 0
      ? 15 + Math.round(((i + 1) / diff.files.length) * 35)
      : 50;
    onEvent({
      type: "agent_progress",
      agent: agentId,
      progress,
      message: `Scanned ${i + 1}/${diff.files.length} files`,
      timestamp: new Date().toISOString(),
      traceId,
      spanId,
    });
  }

  onEvent({
    type: "agent_thinking",
    agent: agentId,
    thought: `Analyzing ${pluralize(diff.files.length, "file")} for ${lens.name.toLowerCase()} issues...`,
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  onEvent({
    type: "agent_progress",
    agent: agentId,
    progress: 60,
    message: "Dispatching to model",
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  const prompt = buildReviewPrompt(lens, diff, projectContext);

  let progressTimer: ReturnType<typeof setInterval> | null = null;
  const timerStart = Date.now();
  const progressStages = [
    { afterMs: 2000, progress: 70, message: "Model analyzing patterns" },
    { afterMs: 5000, progress: 80, message: "Scoring potential issues" },
    { afterMs: 8000, progress: 90, message: "Synthesizing findings" },
    { afterMs: 11000, progress: 95, message: "Final checks" },
  ];
  let stageIndex = 0;
  progressTimer = setInterval(() => {
    if (signal?.aborted) { clearInterval(progressTimer!); return; }
    const elapsedMs = Date.now() - timerStart;
    if (stageIndex >= progressStages.length) return;
    const stage = progressStages[stageIndex];
    if (stage && elapsedMs >= stage.afterMs) {
      stageIndex += 1;
      onEvent({
        type: "agent_progress",
        agent: agentId,
        progress: stage.progress,
        message: stage.message,
        timestamp: new Date().toISOString(),
        traceId,
        spanId,
      });
    }
  }, 500);

  let result: Result<ReviewResult, AIError>;
  try {
    result = await client.generate(prompt, ReviewResultSchema, { signal });
  } finally {
    if (progressTimer) clearInterval(progressTimer);
  }

  if (!result.ok) {
    const errorLabel = result.error.code ? `${result.error.code}: ${result.error.message}` : result.error.message;
    onEvent({
      type: "agent_error",
      agent: agentId,
      error: errorLabel,
      timestamp: new Date().toISOString(),
      traceId,
      spanId,
    });
    return result;
  }

  const diffFilePaths = new Set(diff.files.map((f) => f.filePath));
  const issuesWithEvidence = result.value.issues
    .filter((issue: ReviewIssue) => diffFilePaths.has(issue.file))
    .map((issue: ReviewIssue) => ensureIssueEvidence(issue, diff));

  for (const issue of issuesWithEvidence) {
    onEvent({
      type: "issue_found",
      agent: agentId,
      issue,
      timestamp: new Date().toISOString(),
      traceId,
      spanId,
    });
  }

  onEvent({
    type: "agent_progress",
    agent: agentId,
    progress: 90,
    message: `Found ${pluralize(issuesWithEvidence.length, "issue")}`,
    timestamp: new Date().toISOString(),
    traceId,
    spanId,
  });

  onEvent({
    type: "agent_complete",
    agent: agentId,
    issueCount: issuesWithEvidence.length,
    timestamp: new Date().toISOString(),
    durationMs: Date.now() - startedAt,
    promptChars: prompt.length,
    outputChars: JSON.stringify(result.value).length,
    tokenEstimate: estimateTokens(prompt),
    traceId,
    spanId,
  });

  return ok({
    lensId: lens.id,
    lensName: lens.name,
    summary: result.value.summary,
    issues: issuesWithEvidence,
  });
}

