import { AGENT_METADATA, LENS_TO_AGENT } from "@diffgazer/core/schemas/events";
import type { LensId, ReviewIssue, ReviewOptions } from "@diffgazer/core/schemas/review";
import type { AIClient } from "../ai/types.js";
import type { ParsedDiff } from "../diff/types.js";
import { runLensAnalysis } from "./analysis.js";
import { deduplicateIssues, filterIssuesByMinSeverity, sortIssuesBySeverity, validateIssueCompleteness } from "./issues.js";
import { getLenses } from "./lenses.js";
import type { OrchestrationOptions, OrchestrationOutcome, ReviewError } from "./types.js";

async function runWithConcurrency<T, R>(
  items: T[],
  limit: number,
  worker: (item: T, index: number) => Promise<R>,
  signal?: AbortSignal
): Promise<PromiseSettledResult<R>[]> {
  const results: PromiseSettledResult<R>[] = new Array(items.length);
  let nextIndex = 0;
  let active = 0;

  return new Promise((resolve) => {
    const resolveWithFill = () => {
      for (let i = 0; i < results.length; i++) {
        if (!results[i]) {
          results[i] = { status: "rejected", reason: new Error("Aborted") };
        }
      }
      resolve(results);
    };

    const launchNext = () => {
      if (signal?.aborted) {
        if (active === 0) resolveWithFill();
        return;
      }

      if (nextIndex >= items.length && active === 0) {
        resolve(results);
        return;
      }

      while (active < limit && nextIndex < items.length) {
        const currentIndex = nextIndex++;
        active++;
        Promise.resolve(worker(items[currentIndex]!, currentIndex))
          .then((value) => {
            results[currentIndex] = { status: "fulfilled", value };
          })
          .catch((reason) => {
            results[currentIndex] = { status: "rejected", reason };
          })
          .finally(() => {
            active--;
            launchNext();
          });
      }
    };

    launchNext();
  });
}

export async function orchestrateReview(
  client: AIClient,
  diff: ParsedDiff,
  reviewOptions: ReviewOptions = {},
  onEvent: (event: AgentStreamEvent | StepEvent) => void,
  orchestrationOptions: OrchestrationOptions,
): Promise<Result<OrchestrationOutcome, ReviewError>> {
  if (diff.files.length === 0) {
    return err({ code: "NO_DIFF", message: "No files changed" });
  }

  const lensIds = reviewOptions.lenses ?? reviewOptions.profile?.lenses ?? ["correctness"];
  const lenses = getLenses(lensIds);
  const filter = reviewOptions.filter ?? reviewOptions.profile?.filter;

  const traceId = randomUUID();
  const orchestratorSpanId = randomUUID();
  const concurrency = Math.min(orchestrationOptions.concurrency, Math.max(1, lenses.length));

  onEvent({
    type: "orchestrator_start",
    agents: lenses.map((lens) => AGENT_METADATA[LENS_TO_AGENT[lens.id]]),
    concurrency,
    timestamp: new Date().toISOString(),
    traceId,
    spanId: orchestratorSpanId,
  });

  const tasks = lenses.map((lens, index) => {
    const agentId = LENS_TO_AGENT[lens.id];
    const agentMeta = AGENT_METADATA[agentId];
    const spanId = randomUUID();

    onEvent({
      type: "agent_queued",
      agent: agentMeta,
      position: index + 1,
      total: lenses.length,
      timestamp: new Date().toISOString(),
      traceId,
      spanId,
    });

    return { lens, agentId, spanId };
  });

  const settledResults = await runWithConcurrency(
    tasks,
    concurrency,
    async (task) => {
      try {
        return await runLensAnalysis(client, task.lens, diff, onEvent, {
          traceId,
          spanId: task.spanId,
          parentSpanId: orchestratorSpanId,
        }, orchestrationOptions.projectContext, orchestrationOptions.signal);
      } catch (error) {
        onEvent({
          type: "agent_error",
          agent: task.agentId,
          error: String(error),
          timestamp: new Date().toISOString(),
          traceId,
          spanId: task.spanId,
        });
        throw error;
      }
    },
    orchestrationOptions.signal,
  );

  const allIssues: ReviewIssue[] = [];
  const summaries: string[] = [];
  const lensStats: LensStat[] = [];
  const failedLenses: Array<{ lensId: LensId; errorCode?: string; errorMessage?: string }> = [];
  let lastError: ReviewError | null = null;

  settledResults.forEach((settled, i) => {
    const lens = lenses[i];
    if (!lens) return;

    if (settled.status === "rejected") {
      const errorMsg = getErrorMessage(settled.reason);
      lastError = { code: "NETWORK_ERROR", message: errorMsg };
      lensStats.push({ lensId: lens.id, issueCount: 0, status: "failed", errorCode: "NETWORK_ERROR", errorMessage: errorMsg });
      failedLenses.push({ lensId: lens.id, errorCode: "NETWORK_ERROR", errorMessage: errorMsg });
      return;
    }

    const result = settled.value;
    if (!result.ok) {
      lastError = result.error;
      lensStats.push({ lensId: lens.id, issueCount: 0, status: "failed", errorCode: result.error.code, errorMessage: result.error.message });
      failedLenses.push({ lensId: lens.id, errorCode: result.error.code, errorMessage: result.error.message });
      return;
    }

    allIssues.push(...result.value.issues);
    summaries.push(`[${result.value.lensName}] ${result.value.summary}`);
    lensStats.push({ lensId: result.value.lensId, issueCount: result.value.issues.length, status: "success" });
  });

  const deduplicated = deduplicateIssues(allIssues);
  const filtered = filterIssuesByMinSeverity(deduplicated, filter);
  const validated = filtered.filter(validateIssueCompleteness);
  const sorted = sortIssuesBySeverity(validated);

  const failedSummary = failedLenses.length > 0
    ? `Partial analysis: ${failedLenses.map((f) => `${f.lensId}${f.errorCode ? ` (${f.errorCode})` : ""}`).join(", ")} failed.`
    : "";
  const combinedSummary = [summaries.join("\n\n"), failedSummary].filter(Boolean).join("\n\n");

  onEvent({
    type: "orchestrator_complete",
    summary: combinedSummary,
    totalIssues: sorted.length,
    lensStats,
    filesAnalyzed: diff.files.length,
    timestamp: new Date().toISOString(),
    traceId,
    spanId: orchestratorSpanId,
  });

  const allLensesFailed = failedLenses.length === lenses.length && lenses.length > 0;

  if (allLensesFailed && lastError !== null) {
    if (orchestrationOptions.partialOnAllFailed) {
      return ok({
        summary: combinedSummary || `Analysis incomplete: ${getErrorMessage(lastError)}`,
        issues: [],
        lensStats,
        failedLenses,
      });
    }
    return err(lastError);
  }

  return ok({
    summary: combinedSummary,
    issues: sorted,
    lensStats,
    failedLenses,
  });
}

import { mkdirSync, mkdtempSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { Hono } from "hono";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { PROJECT_ROOT_HEADER } from "../lib/paths.js";

let diffgazerHome: string;
let projectRoot: string;

async function createApp(): Promise<Hono> {
  const { requireSetup } = await import("./setup-guard.js");
  const app = new Hono();
  app.use("/*", requireSetup);
  app.get("/test", (ctx) => ctx.json({ ok: true }));
  return app;
}

async function configureReadySetup(): Promise<void> {
  const store = (await import("../lib/config/store.js")).getStore();
  await store.updateSettings({ secretsStorage: "file" });
  await store.saveProviderCredentials({
    provider: "gemini",
    apiKey: "sk-test",
    model: "gemini-2.5-flash",
  });
  const project = store.ensureProjectFile(projectRoot);
  await store.saveTrust({
    projectId: project.projectId!,
    repoRoot: projectRoot,
    trustedAt: "2024-01-01T00:00:00.000Z",
    capabilities: { readFiles: true, runCommands: false },
    trustMode: "persistent",
  });
}

async function request(app: Hono): Promise<Response> {
  return app.request("/test", {
    headers: { [PROJECT_ROOT_HEADER]: projectRoot },
  });
}

describe("requireSetup", () => {
  let warnSpy: ReturnType<typeof vi.spyOn>;

  beforeEach(() => {
    diffgazerHome = mkdtempSync(join(tmpdir(), "diffgazer-setup-home-"));
    projectRoot = mkdtempSync(join(tmpdir(), "diffgazer-setup-project-"));
    mkdirSync(join(projectRoot, ".git"));
    process.env.DIFFGAZER_HOME = diffgazerHome;
    process.env.DIFFGAZER_DEV_UNSAFE_PROJECT_ROOT = "1";
    // Suppress fire-and-forget persistence warnings emitted after teardown removes the temp dir.
    // The config store dispatches persist*Async without awaiting, so a pending write can land
    // after rmSync; production keeps this UX-friendly fire-and-forget pattern unchanged.
    warnSpy = vi.spyOn(console, "warn").mockImplementation(() => {});
    vi.resetModules();
  });

  afterEach(() => {
    delete process.env.DIFFGAZER_HOME;
    delete process.env.DIFFGAZER_DEV_UNSAFE_PROJECT_ROOT;
    rmSync(diffgazerHome, { recursive: true, force: true });
    rmSync(projectRoot, { recursive: true, force: true });
    warnSpy.mockRestore();
  });

  it("blocks requests until setup has storage, provider, model, and trust", async () => {
    const app = await createApp();

    const response = await request(app);
    const body = await response.json() as {
      error: { code: string; message: string };
    };

    expect(response.status).toBe(503);
    expect(body.error.code).toBe("SETUP_REQUIRED");
    expect(body.error.message).toContain("secretsStorage");
    expect(body.error.message).toContain("provider");
    expect(body.error.message).toContain("model");
    expect(body.error.message).toContain("trust");
  });

  it("passes requests once setup is ready", async () => {
    await configureReadySetup();
    const app = await createApp();

    const response = await request(app);
    const body = await response.json() as { ok: boolean };

    expect(response.status).toBe(200);
    expect(body).toEqual({ ok: true });
  });
});

